import React, { useState } from 'react';
import LanguageSwitcher from './LanguageSwitcher';

function Filter({ onClose }) {
  const [ageMin, setAgeMin] = useState(18);
  const [ageMax, setAgeMax] = useState(50);
  const [city, setCity] = useState('');
  const [gender, setGender] = useState('');

  return (
    <div style={styles.overlay}>
      <div style={styles.modal}>
        <button style={styles.closeBtn} onClick={onClose}>✕</button>
        <h2 style={styles.title}>🔍 Filtrer</h2>
        <LanguageSwitcher />
        <div style={styles.group}>
          <label>Âge</label>
          <div style={{ display: 'flex', gap: 10 }}>
            <input type="number" value={ageMin} onChange={(e) => setAgeMin(Number(e.target.value))} style={styles.rangeInput} />
            <span>-</span>
            <input type="number" value={ageMax} onChange={(e) => setAgeMax(Number(e.target.value))} style={styles.rangeInput} />
          </div>
        </div>
        <div style={styles.group}>
          <label>📍 Ville</label>
          <input type="text" placeholder="Toutes" value={city} onChange={(e) => setCity(e.target.value)} style={styles.input} />
        </div>
        <div style={styles.group}>
          <label>👤 Genre</label>
          <div style={{ display: 'flex', gap: 10 }}>
            <button onClick={() => setGender('femme')} style={{ ...styles.genderBtn, background: gender === 'femme' ? '#FF69B4' : '#f0f0f0', color: gender === 'femme' ? 'white' : '#333' }}>👩 Femme</button>
            <button onClick={() => setGender('homme')} style={{ ...styles.genderBtn, background: gender === 'homme' ? '#4A90D9' : '#f0f0f0', color: gender === 'homme' ? 'white' : '#333' }}>👨 Homme</button>
            <button onClick={() => setGender('')} style={{ ...styles.genderBtn, background: gender === '' ? '#6C63FF' : '#f0f0f0', color: gender === '' ? 'white' : '#333' }}>🌍 Tous</button>
          </div>
        </div>
        <button style={styles.applyBtn} onClick={() => { alert('🔍 Filtres appliqués'); onClose(); }}>🔍 Appliquer</button>
      </div>
    </div>
  );
}

const styles = {
  overlay: { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.7)', backdropFilter: 'blur(10px)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 999, padding: 20 },
  modal: { background: 'white', borderRadius: 30, padding: 40, maxWidth: 450, width: '100%', position: 'relative' },
  closeBtn: { position: 'absolute', top: 15, right: 20, background: 'none', border: 'none', fontSize: 30, cursor: 'pointer', color: '#999' },
  title: { fontSize: '2rem', fontWeight: 'bold', marginBottom: 10, background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', textAlign: 'center' },
  group: { marginBottom: 20 },
  input: { width: '100%', padding: 12, borderRadius: 10, border: '2px solid #ddd', fontSize: '1rem', outline: 'none', boxSizing: 'border-box' },
  rangeInput: { flex: 1, padding: 12, borderRadius: 10, border: '2px solid #ddd', fontSize: '1rem', textAlign: 'center', width: 60 },
  genderBtn: { flex: 1, padding: 10, borderRadius: 10, border: 'none', fontSize: '0.9rem', fontWeight: 'bold', cursor: 'pointer' },
  applyBtn: { width: '100%', padding: 15, borderRadius: 12, border: 'none', background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', fontSize: '1.2rem', fontWeight: 'bold', cursor: 'pointer' },
};

export default Filter;
